            loadTokens: function () {

                app.global.tokensCollection = new app.collections.tokens;

                app.global.tokensCollection.fetch();

            },

            setVersions: function () {

                app.global.versionsCollection = new app.collections.versions;

                app.global.versionsCollection.fetch();
                if (app.global.versionsCollection.length > 0) {
                    app.global.versionsCollection.each(
                        function (e) {
                            e.destroy();
                        }
                    );
                }

                var t = new app.models.version({
                    version: app.const.version.responseText
                });
                app.global.versionsCollection.add(t);
                t.save();

            },
            getLanguage: function () {
        
                app.global.languagesCollection = new app.collections.languages;
                app.global.languagesCollection.fetch();
                var e = app.global.default_language();
                if (app.global.languagesCollection.length > 0) {
                    e = app.global.languagesCollection.at(0).get("lang");
                    if ($.inArray(e, app.languages) === -1) {
                        e = app.global.default_language();
                        this.setLanguage(e);
                    }
                } else {
                    this.setLanguage(e);
                }
                return e;
            },
            setLanguage: function (e) {
                app.global.languagesCollection = new app.collections.languages;
                app.global.languagesCollection.fetch();
                if (app.global.languagesCollection.length > 0) {
                    app.global.languagesCollection.each(
                        function (e) {
                            e.destroy();
                        }
                    );
                }
                if (!_.contains(app.languages, e)) {
                    e = app.global.default_language();
                }
                var t = new app.models.language({ lang: e });
            //  console.log(t);
                app.global.languagesCollection.add(t);
                t.save();
            },
            loadTemplate: function (e, t) {
          
                var n = app.utils.getLanguage();
                var r = []; 
                $.each(e, function (e, t) {
                
                    if (app.views[t]) {
                        r.push($.get("js/templates/" + n + "/app.templates." + t + ".html",
                            function (e) { app.views[t].prototype.template = _.template(e); }));
                    }
                    else { alert(t + " not found for " + "js/templates/" + n + "/app.templates." + t + ".html"); }
                });
                $.when.apply(null, r).done(t);
            },
            loadLanguage: function (e, t) {
                var n = app.utils.getLanguage();
                var r = []; $.each(e, function (e, t) {
                    if (app.views[t]) {
                        r.push(
                            $.getJSON("js/languages/" + n + "/app.languages." + t + ".json",
                            function (e) { app.views[t].prototype.language = e; }));
                    }
                    else { alert(t + " not found (loadLanguage)"+app.views[t]); }
                });
                $.when.apply(null, r).done(t);
            },

